package com.chaobo.scm.supplier.infrastructure.persistence.contract;import org.apache.ibatis.annotations.*;import java.time.*;import java.math.*;
@Mapper public interface PriceAgreementProjectionMapper{record Header(String ref,long contractId,long quoteId,long supplierId,String currency,LocalDate from,LocalDate to,int status,int version){}record Line(long agreementId,String sku,BigDecimal price,BigDecimal tax,BigDecimal moq,int days){}@Select("SELECT agreement_id FROM sup_price_agreement WHERE contract_id=#{contractId}")Long agreementId(long contractId);@Insert("INSERT INTO sup_price_agreement(agreement_ref,contract_id,quote_id,supplier_id,currency,effective_from,effective_to,agreement_status,source_contract_version) VALUES(#{h.ref},#{h.contractId},#{h.quoteId},#{h.supplierId},#{h.currency},#{h.from},#{h.to},#{h.status},#{h.version}) ON DUPLICATE KEY UPDATE effective_from=VALUES(effective_from),effective_to=VALUES(effective_to),agreement_status=VALUES(agreement_status),source_contract_version=VALUES(source_contract_version)")void upsert(@Param("h")Header h);@Insert("INSERT INTO sup_price_agreement_line(agreement_id,sku_code,unit_price,tax_rate,moq,delivery_days) VALUES(#{l.agreementId},#{l.sku},#{l.price},#{l.tax},#{l.moq},#{l.days}) ON DUPLICATE KEY UPDATE unit_price=VALUES(unit_price),tax_rate=VALUES(tax_rate),moq=VALUES(moq),delivery_days=VALUES(delivery_days)")void upsertLine(@Param("l")Line l);@Update("UPDATE sup_price_agreement SET effective_to=#{to},source_contract_version=#{version} WHERE contract_id=#{contractId} AND agreement_status=1")void renew(@Param("contractId")long contractId,@Param("to")LocalDate to,@Param("version")int version);@Update("UPDATE sup_price_agreement SET agreement_status=2,source_contract_version=#{version} WHERE contract_id=#{contractId} AND agreement_status=1")void terminate(@Param("contractId")long contractId,@Param("version")int version);}
